#include <iostream>
#include <vector>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    if (n > 0) {
        int last = a[n - 1];
        for (int i = n - 1; i > 0; --i) {
            a[i] = a[i - 1];
        }
        a[0] = last;
    }

    for (int i = 0; i < n; ++i) {
        if (i > 0) cout << ' ';
        cout << a[i];
    }
    cout << endl;

    return 0;
}
